SELECT sp.id, sp.algorithm_type AS algorithmType, sp.task_name AS taskName, sp.project_id AS projectId, spt.task_id AS taskId, spt.task_state AS taskState, spt.result_rows AS resultRows, spt.create_date AS createDate FROM single_party sp INNER JOIN single_party_task spt ON sp.id = spt.sp_id WHERE spt.is_del = 0
AND sp.task_name LIKE CONCAT('%', #{taskName}, '%')
AND sp.algorithm_type = #{algorithmType}
AND spt.task_state = #{taskState}
AND sp.project_id = #{projectId}
AND spt.create_date >= #{startDate}
AND spt.create_date <= #{endDate}
ORDER BY spt.create_date DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(sp.id)
FROM
    single_party sp
INNER JOIN single_party_task spt ON sp.id = spt.sp_id
WHERE spt.is_del = 0

    AND sp.task_name LIKE CONCAT('%', #{taskName}, '%')


    AND sp.algorithm_type = #{algorithmType}


    AND spt.task_state = #{taskState}


    AND sp.project_id = #{projectId}


    AND spt.create_date >= #{startDate}


    AND spt.create_date <= #{endDate}
